import io
import json
import os

import torch
import torch.nn as nn
import torchvision.transforms as transforms
from PIL import Image
from flask import Flask, request, jsonify

# --- Configuration ---
# Load ImageNet class labels
# This list maps the model's output indices to human-readable class names.
# We attempt to download it, with a fallback to a dummy list if download fails.
IMAGENET_CLASSES_URL = "https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt"
imagenet_classes = []
try:
    import requests
    response = requests.get(IMAGENET_CLASSES_URL)
    response.raise_for_status() # Raise an exception for HTTP errors
    imagenet_classes = [line.strip() for line in response.text.split('\n') if line.strip()]
except Exception as e:
    print(f"Warning: Could not download ImageNet classes from {IMAGENET_CLASSES_URL}. Using dummy classes. Error: {e}")
    imagenet_classes = [f"class_{i}" for i in range(1000)] # Dummy classes if download fails

# --- Model Setup ---
# Load a pre-trained PyTorch model (e.g., ResNet18)
# This model is pre-trained on the ImageNet dataset.
model = torch.hub.load('pytorch/vision:v0.10.0', 'resnet18', pretrained=True)
model.eval() # Set the model to evaluation mode

# Determine device (GPU if available, otherwise CPU)
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model.to(device)

# --- Image Transformation ---
# As per the user's request "without preprocessing or validation",
# we interpret this as "without *additional* or *complex* preprocessing beyond
# what's absolutely necessary for the model to accept the input".
# The following transformations are fundamental for ImageNet pre-trained models
# to correctly process an image into a tensor format they expect.
transform = transforms.Compose([
    transforms.Resize(256),        # Resize the image to 256x256 pixels
    transforms.CenterCrop(224),    # Crop the center 224x224 pixels (standard input size for ResNet)
    transforms.ToTensor(),         # Convert PIL Image to PyTorch Tensor (HWC to CHW, scale to [0,1])
    transforms.Normalize(          # Normalize with ImageNet means and standard deviations
        mean=[0.485, 0.456, 0.406],
        std=[0.229, 0.224, 0.225]
    )
])

# --- Flask App Setup ---
app = Flask(__name__)

@app.route('/classify', methods=['POST'])
def classify_image():
    # Check if an image file was provided in the request
    if 'image' not in request.files:
        # While "no validation" was requested, a missing file is an API usage error
        # that prevents any processing. We return a basic error for this.
        return jsonify({'error': 'No image file provided in the "image" field.'}), 400

    image_file = request.files['image']

    # Read the image file into a PIL Image object
    try:
        image_bytes = image_file.read()
        # Open the image and convert to RGB to ensure 3 channels for the model
        image = Image.open(io.BytesIO(image_bytes)).convert('RGB')
    except Exception as e:
        # Handle cases where the uploaded file is not a valid image or cannot be processed
        return jsonify({'error': f'Could not open or process image file: {e}'}), 400

    # Apply the necessary transformations to prepare the image for the model
    # .unsqueeze(0) adds a batch dimension (B, C, H, W) as models expect batches
    input_tensor = transform(image).unsqueeze(0).to(device)

    # Run inference with the model
    with torch.no_grad(): # Disable gradient calculation for inference to save memory and speed up
        output = model(input_tensor)

    # Get probabilities by applying softmax to the model's raw output (logits)
    probabilities = torch.nn.functional.softmax(output[0], dim=0)

    # Get the predicted class index and its confidence score
    predicted_probability, predicted_class_idx = torch.max(probabilities, 0)

    # Map the predicted class index to its human-readable name
    predicted_class_name = imagenet_classes[predicted_class_idx.item()]
    confidence_score = predicted_probability.item()

    # Return the predicted class and confidence score as a JSON response
    return jsonify({
        'predicted_class': predicted_class_name,
        'confidence_score': confidence_score
    })

# --- Run the Flask App ---
if __name__ == '__main__':
    # For production deployment, it's recommended to use a WSGI server
    # like Gunicorn (e.g., `gunicorn -w 4 -b 0.0.0.0:5000 app:app`).
    # For development, you can run directly:
    app.run(host='0.0.0.0', port=5000, debug=False) # Set debug=False for production environments